scwin.btn_create_order_onclick = function (e) {
  if (scwin.sbmFlag) return;
  if (ds_interTransTargetDetail.getModifiedIndex().length == 0) {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_001, ["오더별 매출"]);
    return;
  }
  if (!scwin.f_validateInterTransTargetDetailInfo("생성")) return;
  scwin.sbmFlag = true;
  ds_bilgcommessage.removeAll();
  $c.sbm.execute($p, sbm_save_order);
};

// 내부거래대상 취소 프로시져 호출-오더별
